INSERT INTO `beranda_content` VALUES ('h-1','Portal Resmi Sespim Lemdiklat Polri','Hero Headline','2026-06-20','Published','Admin','2026-07-08 07:59:27','2026-07-22 02:33:57','/uploads/image-1783951787369-752974222.png','Portal Terpadu untuk Profil Kelembagaan, Program Pendidikan, Widyaiswara, Publikasi, Berita, Kegiatan, Galeri, Unduhan dan Layanan Teknologi Pendidikan Kepemimpinan Polri '),('h-2','Kepala Sekolah Staf dan Pimpinan Polri','General','2026-06-19','Published','Admin','2026-07-08 07:59:27','2026-07-13 14:10:00','/uploads/image-1783951800015-766797363.webp','Assalamu\'alaikum warahmatullahi wabarakatuh,\r\nSalam sejahtera bagi kita semua,\r\nOm Swastiastu, Namo Buddhaya, Salam Kebajikan.\r\n\r\nPuji syukur kita panjatkan ke hadirat Tuhan Yang Maha Esa atas rahmat dan karunia-Nya, sehingga Portal Resmi Sekolah Staf dan Pimpinan Kepolisian Negara Republik Indonesia dapat hadir sebagai media informasi, komunikasi, dan publikasi yang mendukung pelaksanaan pendidikan kepemimpinan di lingkungan Polri. Kehadiran portal ini menjadi bagian dari upaya Sespim Polri dalam memperkuat keterbukaan informasi, meningkatkan layanan digital, serta mendukung tata kelola pendidikan yang modern, efektif, dan responsif.\r\n\r\nSespim Polri memiliki peran strategis dalam menyiapkan kader pemimpin Polri yang profesional, berintegritas, adaptif, serta mampu menjawab tantangan tugas kepolisian yang semakin kompleks. Melalui pendidikan, pelatihan, pengkajian, dan pengembangan kepemimpinan, Sespim Polri berkomitmen membentuk sumber daya manusia yang unggul, visioner, serta memiliki kemampuan manajerial dan kepemimpinan yang kuat dalam mendukung transformasi Polri yang Presisi.\r\n\r\nPortal ini diharapkan menjadi pusat informasi resmi yang mencakup profil lembaga, program pendidikan, kegiatan akademik, agenda kelembagaan, publikasi, serta layanan peserta didik. Selain itu, portal ini juga diharapkan memberikan manfaat bagi peserta didik, tenaga pendidik, pengasuh, personel Sespim Polri, alumni, mitra kerja, dan masyarakat luas, serta menjadi ruang komunikasi yang terbuka, informatif, dan konstruktif dalam mendukung peningkatan kualitas pendidikan kepemimpinan Polri.\r\n\r\nWassalamu\'alaikum warahmatullahi wabarakatuh.\r\n\r\nKepala Sekolah Staf dan Pimpinan Polri\r\nIrjen Pol. Midi Siswoko, S.I.K');
/*!40000 ALTER TABLE `beranda_content` ENABLE KEYS */;
UNLOCK TABLES;

