INSERT INTO `galeri_unduhan_content` VALUES ('g-1','Dokumentasi Upacara Pembukaan Pendidikan','Galeri Foto','2026-07-01','Published','Admin','2026-07-08 07:59:27','2026-07-22 16:47:14',NULL,'JUDUL: Upacara Pembukaan Pendidikan Sespimti TA 2026\nDESKRIPSI: Pembukaan resmi program pendidikan perwira tinggi Sespimti Angkatan Ke-34 bertempat di Gedung Utaryo.\nGAMBAR: /images/sespim-campus-hero.png\nKATEGORI: Upacara\nTANGGAL: 15 Juli 2026\n\nJUDUL: Kunjungan Studi Strategis Dalam Negeri (KKDN) Sespimmen\nDESKRIPSI: Kegiatan kunjungan lapangan peserta didik Dikreg-66 dalam meninjau kesiapan pilkada serentak di Polda Jawa Barat.\nGAMBAR: /images/sespim-smart-class.png\nKATEGORI: Pendidikan\nTANGGAL: 10 Juli 2026\n\nJUDUL: Seminar Nasional Kepemimpinan Polri\nDESKRIPSI: Diskusi panel menghadirkan narasumber nasional membahas strategi pemolisian di era transformasi Society 5.0.\nGAMBAR: /images/pejabat/kasespim.png\nKATEGORI: Seminar\nTANGGAL: 08 Juli 2026'),('g-3','Template NASKAP Serdik Resmi','Template NASKAP','2026-07-02','Published','Admin','2026-07-08 07:59:27','2026-07-22 16:47:14',NULL,'NAMA: Template NASKAP Serdik Resmi 2026\nDESKRIPSI: Format baku Microsoft Word untuk pengetikan naskah karya perorangan (Naskap) peserta didik Sespimmen dan Sespimma.\nFILE: Template_NASKAP_Sespim_2026.docx\nURL: https://drive.google.com/file/d/1Bk8hy7Y9_1HYtZzmRhaAB6foaPpSGmWB/view?usp=sharing\nFORMAT: DOCX\nKATEGORI: Template'),('g-4','Template Policy Brief Lemdiklat','Template Policy Brief','2026-07-02','Published','Admin','2026-07-08 07:59:27','2026-07-22 16:47:14',NULL,'NAMA: Template Policy Brief Lemdiklat\nDESKRIPSI: Format standar penulisan naskah kajian kilat policy brief pimpinan daerah.\nFILE: Template_Policy_Brief_Lemdiklat.docx\nURL: https://drive.google.com/file/d/1Bk8hy7Y9_1HYtZzmRhaAB6foaPpSGmWB/view?usp=sharing\nFORMAT: DOCX\nKATEGORI: Template'),('g-5','Formulir Pendaftaran Ulang / Umum','Formulir Umum','2026-07-03','Published','Admin','2026-07-08 07:59:27','2026-07-22 16:47:14',NULL,'NAMA: Formulir Registrasi Ulang Serdik Baru\nDESKRIPSI: Formulir berkas administrasi dan data pribadi peserta didik baru Sespimti, Sespimmen, dan Sespimma.\nFILE: Formulir_Registrasi_Serdik_Baru.pdf\nURL: https://drive.google.com/file/d/1Bk8hy7Y9_1HYtZzmRhaAB6foaPpSGmWB/view?usp=sharing\nFORMAT: PDF\nKATEGORI: Formulir'),('g-6','Serdik Sespim Video Gallery','Galeri Video','2026-07-22','Published','Denny Chahyo wiebowo','2026-07-22 17:31:58','2026-07-22 17:31:58',NULL,NULL);
