INSERT INTO `sarana_prasarana_content` VALUES ('s-1','eLibrary Katalog Digital SLIMS','eLibrary','2026-06-30','Published','Admin','2026-07-08 07:59:27','2026-07-11 17:10:04','','Tautan dan panduan akses katalog digital perpustakaan Sespim (SLiMS) yang memudahkan pencarian ribuan koleksi buku cetak, referensi, dan naskah dinas.'),('s-2','Portal Perpusnas Indonesia','Perpusnas','2026-07-01','Published','Admin','2026-07-08 07:59:27','2026-07-11 16:58:09',NULL,'Portal integrasi akses ke layanan keanggotaan Perpustakaan Nasional (Perpusnas) RI untuk memfasilitasi kebutuhan referensi ilmiah perwira siswa.'),('s-3','Koleksi Ejurnal Internasional','Ejurnal','2026-07-02','Published','Admin','2026-07-08 07:59:27','2026-07-11 16:58:09',NULL,'Tautan resmi akses database ejurnal internasional terkemuka yang dilanggan Lemdiklat Polri untuk mendukung riset dan penyusunan tugas akhir.'),('s-4','LMS SIAPSESPIM Platform Pembelajaran','LMS SIAPSESPIM','2026-07-02','Published','Admin','2026-07-08 07:59:27','2026-07-11 16:58:09',NULL,'Panduan operasional dan masuk ke Learning Management System (LMS) SIAPSESPIM sebagai platform utama pembelajaran jarak jauh dan ujian digital.'),('s-5','Turnitin Cek Plagiarisme','Cek Plagiarisme','2026-07-01','Published','Admin','2026-07-08 07:59:27','2026-07-22 14:31:21','https://www.turnitin.com/class/53918489/student_home?lang=en_us','Layanan Turnitin mandiri bagi perwira siswa untuk mengecek tingkat plagiarisme dan memverifikasi keaslian naskah sebelum diserahkan ke pembimbing.'),('s-6','Klinik Pratama Sespim Polri','Klinik Pratama','2026-07-03','Published','Admin','2026-07-08 07:59:27','2026-07-11 16:58:09',NULL,'Informasi sarana medis, dokter spesialis, jadwal layanan, dan fasilitas pengobatan rawat jalan di Klinik Pratama Sespim Lemdiklat Polri.'),('s-7','Repositori Produk / Karya Akademis Sespim','Produk / Karya Akademis','2026-07-13','Published','Admin','2026-07-22 17:41:20','2026-07-22 17:41:20',NULL,'NAMA: Buku Saku Taktis Negosiasi Konflik Sosial\nDESKRIPSI: Panduan taktis bagi personel lapangan dalam melakukan negosiasi dan mediasi konflik komunal di masyarakat secara humanis.\nPENULIS: Kombes Pol Dr. Awan Samodra, S.H.\nTAHUN: 2026\nURL: https://drive.google.com/file/d/1Bk8hy7Y9_1HYtZzmRhaAB6foaPpSGmWB/view?usp=sharing\nFILE: Buku_Saku_Negosiasi_Konflik.pdf\nKATEGORI: Buku Saku\nFORMAT: PDF\n\nNAMA: Kajian Strategis Kebijakan ETLE Nasional\nDESKRIPSI: Analisis dampak implementasi ETLE nasional terhadap kepatuhan berkendara dan potensi penerimaan kas negara.\nPENULIS: AKBP Rahmat Hidayat, S.I.K.\nTAHUN: 2026\nURL: https://drive.google.com/file/d/1Bk8hy7Y9_1HYtZzmRhaAB6foaPpSGmWB/view?usp=sharing\nFILE: Kajian_Kebijakan_ETLE_Nasional.pdf\nKATEGORI: Kajian\nFORMAT: PDF\n\nNAMA: Naskap Terbaik Dikreg Ke-66: Transformasi Digital Polsek\nDESKRIPSI: Naskah karya perorangan terbaik mengenai implementasi digitalisasi pelayanan kepolisian tingkat sektor di Polsek Lembang.\nPENULIS: Kompol Dian Prasetyo, S.I.K.\nTAHUN: 2026\nURL: https://drive.google.com/file/d/1Bk8hy7Y9_1HYtZzmRhaAB6foaPpSGmWB/view?usp=sharing\nFILE: Naskap_Dikreg66_Digitalisasi_Polsek.pdf\nKATEGORI: Naskap\nFORMAT: PDF');
