INSERT INTO `widyaiswara_content` VALUES ('w-1','Profil Tenaga Pendidik','Profil Widyaiswara','2026-07-01','Published','Admin','2026-07-08 07:59:27','2026-07-11 16:58:09',NULL,'Profil lengkap, daftar biodata, pangkat, dan riwayat jabatan seluruh Widyaiswara serta instruktur pendidik di lingkungan Sespim Lemdiklat Polri yang berdedikasi tinggi.'),('w-2','Daftar Kompetensi & Bidang Keahlian','Bidang Keahlian','2026-07-02','Published','Admin','2026-07-08 07:59:27','2026-07-11 16:58:09',NULL,'Informasi sebaran bidang keahlian Widyaiswara Sespim yang mencakup hukum kepolisian, manajemen strategis, teknologi siber, sosiologi keamanan, dan taktik operasional.'),('w-3','Publikasi Karya Widyaiswara','Publikasi Widyaiswara','2026-07-02','Published','Admin','2026-07-08 07:59:27','2026-07-11 16:58:09',NULL,'Kumpulan artikel ilmiah, buku, jurnal, dan policy brief yang ditulis oleh para Widyaiswara Sespim Lemdiklat Polri sebagai sumbangsih pemikiran bagi Polri.'),('w-4','Materi Terbuka Widyaiswara','Materi Terbuka pembelajaran Widyiaswara','2026-06-19','Published','Admin','2026-07-08 07:59:27','2026-07-22 16:20:33','','NAMA: RENCANA PEMBELAJARAN WIDYAISWARA.pdf\r\nDESKRIPSI: RANCANG BANGUN PEMBELAJARAN MATA PELATIHAN dan RENCANA PEMBELAJARAN.\r\nFILE: 1. RENCANA PEMBELAJARAN WIDYAISWARA.pdf\r\nURL: https://drive.google.com/file/d/1EJO-u1Z1WKTY0MS7ctyrgswZXdTxcNai/view?usp=drive_link\r\nFORMAT: PDF\r\nKATEGORI: Pelatihan Dasar\r\n\r\nNAMA: PRAKTIK MICROTEACHING\r\nDESKRIPSI: MATA PELATIHAN PRAKTIK MENGAJAR (MICRO TEACHING).\r\nFILE: 2. PRAKTIK MICROTEACHING.pdf\r\nURL: https://drive.google.com/file/d/1gK6HFGZT6UypjCOcee_7Nsjun3EB2PSp/view?usp=drive_link\r\nFORMAT: PDF\r\nKATEGORI: Pelatihan Dasar\r\n\r\nNAMA: PANDUAN PENYUSUNAN MEDIA PEMBELAJARAN.pdf\r\nDESKRIPSI: MATA PELATIHAN PENYUSUNAN MEDIA PEMBELAJARAN.\r\nFILE: 3. PANDUAN PENYUSUNAN MEDIA PEMBELAJARAN.pdf\r\nURL: https://drive.google.com/file/d/1KskM10daUL8RBvt1aYLTrp84XIJdKOUU/view?usp=drive_link\r\nFORMAT: PDF\r\nKATEGORI